// PRODUK DETAIL
Route::get('/produk/{id}', function ($id) {

    $produk = [
        1 => [
            'nama' => 'Palu',
            'gambar' => 'data:image/jpeg;base64,',
            'deskripsi' => 'Palu berkualitas tinggi.'
        ],
        2 => [
            'nama' => 'Gergaji',
            'gambar' => 'data:image/jpeg;base64,',
            'deskripsi' => 'Gergaji tajam super.'
        ],
        3 => [
            'nama' => 'Besi',
            'gambar' => 'data:image/jpeg;base64,',
            'deskripsi' => 'Besi premium.'
        ],
    ];

    $item = $produk[$id] ?? null;

    if (!$item) {
        abort(404);
    }

    return view('produk.show', compact('item'));
});